export type InventoryRpcReceipt = { data: OperatingData; balances: StockBalance[]; movements: OperatingData["stockMovements"]; activity: OperatingData["activity"][number] | undefined; idempotent: boolean };
async function inventoryReceipt(result: unknown, balanceIds: string[]): Promise<InventoryRpcReceipt> {
  const data = await readNormalizedOperatingData(); const receipt = (result || {}) as Row;
  const movementIds = Array.isArray(receipt.movement_ids) ? receipt.movement_ids.map(String) : receipt.movement_id ? [String(receipt.movement_id)] : [];
  const eventId = text(receipt.activity_event_id);
  return { data, balances: data.balances.filter((balance) => balanceIds.includes(balance.id)), movements: movementIds.length ? data.stockMovements.filter((movement) => movementIds.includes(movement.id)) : [], activity: eventId ? data.activity.find((event) => event.id === eventId) : undefined, idempotent: Boolean(receipt.idempotent) };
}
export async function applyInventoryMutationRpc(input: { balanceId: string; action: "adjust" | "cycle_count" | "damage" | "quarantine" | "release_quarantine" | "lost" | "found" | "location"; quantity: number; reason: string; destinationLocationId?: string; idempotencyKey?: string }) {
  const { client } = await context(); const { data, error } = await client.rpc("mutate_inventory_balance", { p_balance_id: input.balanceId, p_action: input.action, p_quantity: input.quantity, p_reason: input.reason, p_destination_location_id: input.destinationLocationId || null, p_idempotency_key: input.idempotencyKey || crypto.randomUUID() });
  if (error) throw new Error(`Inventory ${input.action} failed: ${error.message}`);
  return inventoryReceipt(data, [input.balanceId]);
}
export async function applyInventoryTransferRpc(input: { sourceBalanceId: string; destinationBalanceId: string; quantity: number; reason: string; idempotencyKey?: string }) {
  const { client } = await context(); const { data, error } = await client.rpc("transfer_inventory_balance", { p_source_balance_id: input.sourceBalanceId, p_destination_balance_id: input.destinationBalanceId, p_quantity: input.quantity, p_reason: input.reason, p_idempotency_key: input.idempotencyKey || crypto.randomUUID() });
  if (error) throw new Error(`Inventory transfer failed: ${error.message}`);
  return inventoryReceipt(data, [input.sourceBalanceId, input.destinationBalanceId]);
}

