export async function applyOrderTransition(orderId: string, next: OrderStatus, detail = "", idempotencyKey = crypto.randomUUID()) {
  const { client } = await context(); const { error } = await client.rpc("transition_order_status", { p_order_id: orderId, p_next_status: next, p_detail: detail, p_idempotency_key: idempotencyKey }); if (error) throw new Error(`Order transition failed: ${error.message}`); return readNormalizedOperatingData();
}
export async function applyCreateOrderRpc(input: { number?: string; marketplace: string; customer: { name: string; email?: string }; items: { variantId: string; listingId?: string; title?: string; quantity: number; unitSellingPrice: number; unitCost?: number; discountAllocation?: number; taxAllocation?: number; marketplaceFeeAllocation?: number; paymentFeeAllocation?: number }[]; shippingCharged?: number; shippingCost?: number; marketplaceFee?: number; paymentFee?: number; taxCollected?: number; shipBy?: string; notes?: string; idempotencyKey?: string }) {
  const { businessId, client } = await context(); const payload = { business_id: businessId, external_order_id: input.number, marketplace: input.marketplace, customer: input.customer, items: input.items.map((item) => ({ variant_id: item.variantId, listing_id: item.listingId, title: item.title, quantity: item.quantity, unit_price: item.unitSellingPrice, unit_cost: item.unitCost, discount: item.discountAllocation, tax: item.taxAllocation, marketplace_fee: item.marketplaceFeeAllocation, payment_fee: item.paymentFeeAllocation })), shipping_charged: input.shippingCharged, shipping_cost: input.shippingCost, marketplace_fee: input.marketplaceFee, payment_fee: input.paymentFee, tax_collected: input.taxCollected, ship_by: input.shipBy, notes: input.notes };
  const { error } = await client.rpc("create_order_transactional", { p_order: payload, p_idempotency_key: input.idempotencyKey || crypto.randomUUID() }); if (error) throw new Error(`Order creation failed: ${error.message}`); return readNormalizedOperatingData();
}
export async function applyOrderRefundRpc(orderId: string, input: { amount: number; reason: string; itemId?: string; quantity?: number; shippingAmount?: number; feeAdjustment?: number; externalRefundId?: string; idempotencyKey?: string }) { const { client } = await context(); const { error } = await client.rpc("create_order_refund_transactional", { p_order_id: orderId, p_amount: input.amount, p_reason: input.reason, p_order_item_id: input.itemId || null, p_quantity: input.quantity || null, p_shipping_amount: input.shippingAmount || 0, p_fee_adjustment: input.feeAdjustment || 0, p_external_ref: input.externalRefundId || null, p_idempotency_key: input.idempotencyKey || crypto.randomUUID() }); if (error) throw new Error(`Refund failed: ${error.message}`); return readNormalizedOperatingData(); }
export async function applyReturnReceiptRpc(returnId: string, dispositions: { itemId: string; quantity: number; disposition: "available" | "damaged" | "quarantine" }[], idempotencyKey = crypto.randomUUID()) { const { client } = await context(); const input = Object.fromEntries(dispositions.map((entry) => [entry.itemId, { quantity: entry.quantity, disposition: entry.disposition }])); const { error } = await client.rpc("receive_order_return_transactional", { p_return_id: returnId, p_dispositions: input, p_idempotency_key: idempotencyKey }); if (error) throw new Error(`Return receipt failed: ${error.message}`); return readNormalizedOperatingData(); }
export async function applyFulfillmentMutationRpc(action: string, payload: Row, idempotencyKey = crypto.randomUUID()) {
  const { businessId, client } = await context();
  const { data, error } = await client.rpc("mutate_fulfillment_transactional", { p_business_id: businessId, p_action: action, p_payload: payload, p_idempotency_key: idempotencyKey });
  if (error) throw new Error(`Fulfillment ${action} failed: ${error.message}`);
  void data;
  return readNormalizedOperatingData();
}
